438	  describe('marker visibility setting', function () {
439	    // Markers read well as "a crown on the guide line" for a branch node,
440	    // but add little for a leaf — most leaf atom kinds already carry their
441	    // own native visual style. `markerVisibility` (mode-registry.ts) is a
442	    // real, persisted, live setting so it's triable against a real vault
443	    // without a rebuild.
444	    async function setVisibilityAndNudge(visibility: string): Promise<void> {
445	      await browser.executeObsidian(async ({ plugins }, v) => {
446	        await (plugins.trueOutliner as any).setMarkerVisibility(v);
447	      }, visibility);
448	      await browser.pause(150);
449	    }
450	
451	    afterEach(async function () {
452	      await setVisibilityAndNudge('all'); // leave the vault on the default for other specs
453	    });
454	
455	    it("'with-children': only branch nodes get a marker, regardless of kind", async function () {
456	      const note = 'Scratch/markers-visibility-with-children.md';
457	      const md = [
458	        '# Heading with a child',
459	        '',
460	        'child para (this heading is a branch)',
461	        '',
462	        'Leaf paragraph, no children.',
463	        '',
464	        '```js',
465	        'code line',
466	        '```',
467	        '',
468	      ].join('\n');
469	      await h.createNote(note, md);
470	      await ensureOutlineMode(note);
471	      await setVisibilityAndNudge('with-children');
472	      await browser.pause(150);
473	
474	      // Lines: 0 heading (branch), 2 child para (leaf), 4 leaf para (leaf),
475	      // 6 code opener (leaf — atoms can never have children).
476	      expect((await h.getLineChildRects(0, MARKER_ICON_SELECTOR)).length).toBe(1);
477	      expect((await h.getLineChildRects(2, MARKER_ICON_SELECTOR)).length).toBe(0);
478	      expect((await h.getLineChildRects(4, MARKER_ICON_SELECTOR)).length).toBe(0);
479	      expect((await h.getLineChildRects(6, MARKER_ICON_SELECTOR)).length).toBe(0);
480	    });
481	
482	    it("'with-children': a widget-replaced atom (table) with children obviously still gets no marker — atoms are always leaves", async function () {
483	      const note = 'Scratch/markers-visibility-table-leaf.md';
484	      await h.createNote(note, '| a | b |\n| --- | --- |\n| 1 | 2 |\n');
485	      await ensureOutlineMode(note);
486	      await setVisibilityAndNudge('with-children');
487	      await browser.pause(150);
488	
489	      const rect = await h
490	        .getContentChildRect('.cm-embed-block.cm-table-widget .to-decor-marker-icon', 0)
491	        .catch(() => null);
492	      expect(rect).toBeNull();
493	    });
494	
495	    it("'headings-and-paragraphs': only those two kinds get a marker, leaf or not — atoms never do", async function () {
496	      const note = 'Scratch/markers-visibility-headings-paragraphs.md';
497	      const md = [
498	        '# Heading, no children of its own text',
499	        '',
500	        'A paragraph.',
501	        '',
502	        '> A quoted line',
503	        '',
504	      ].join('\n');
505	      await h.createNote(note, md);
506	      await ensureOutlineMode(note);
507	      await setVisibilityAndNudge('headings-and-paragraphs');
508	      await browser.pause(150);
509	
510	      // Lines: 0 heading, 2 paragraph, 4 quote (an atom — excluded even
511	      // though it's a leaf, same as every other atom kind).
512	      expect((await h.getLineChildRects(0, MARKER_ICON_SELECTOR)).length).toBe(1);
513	      expect((await h.getLineChildRects(2, MARKER_ICON_SELECTOR)).length).toBe(1);
514	      expect((await h.getLineChildRects(4, MARKER_ICON_SELECTOR)).length).toBe(0);
515	
516	      const tableNote = 'Scratch/markers-visibility-headings-paragraphs-table.md';
517	      await h.createNote(tableNote, '| a | b |\n| --- | --- |\n| 1 | 2 |\n');
518	      await ensureOutlineMode(tableNote);
519	      // Explicit re-nudge on the newly-active note, not just relying on the
520	      // setting's own persistence across the note switch — keeps this
521	      // assertion unambiguous about what triggered the recompute.
522	      await setVisibilityAndNudge('headings-and-paragraphs');
523	      // Poll rather than sleep a fixed duration: the table widget's own DOM
524	      // can settle asynchronously after our decoration patch runs, and a
525	      // fixed pause is a race against however long that happens to take
526	      // (worse under system load) — see waitForContentChildCount's own doc
527	      // comment in helpers.ts.
528	      await h.waitForContentChildCount(
529	        '.cm-embed-block.cm-table-widget .to-decor-marker-icon',
530	        0,
531	      );
532	    });
533	
534	    it('changing marker visibility live (no rebuild) toggles a leaf marker on the very next edit', async function () {
535	      const note = 'Scratch/markers-visibility-live-switch.md';
536	      await h.createNote(note, '# Heading\n\nLeaf paragraph.\n');
537	      await ensureOutlineMode(note);
538	      await browser.pause(150);
539	
540	      await setVisibilityAndNudge('all');
541	      expect((await h.getLineChildRects(2, MARKER_ICON_SELECTOR)).length).toBe(1);
542	
543	      await setVisibilityAndNudge('with-children');
544	      expect((await h.getLineChildRects(2, MARKER_ICON_SELECTOR)).length).toBe(0);
545	      // The branch heading keeps its marker throughout.
546	      expect((await h.getLineChildRects(0, MARKER_ICON_SELECTOR)).length).toBe(1);
547	    });
548	
549	    it('hiding a marker never reflows the reserved gutter — text position is unaffected', async function () {
550	      // Real design decision this guards: markerVisibility only gates
551	      // whether the icon is DRAWN, never the gutter reservation itself —
552	      // otherwise toggling the setting would shift indentation/text
553	      // position, not just show/hide an icon.
554	      const note = 'Scratch/markers-visibility-gutter-stable.md';
555	      await h.createNote(note, 'Leaf paragraph.\n');
556	      await ensureOutlineMode(note);
557	      await browser.pause(150);
558	
559	      const paddingWithMarker = await h.getLineComputedStyle(0, 'padding-left');
560	      await setVisibilityAndNudge('with-children'); // this leaf loses its marker
